using System;
using System.Collections.Generic;
using System.Text.Json;
using System.Text.Json.Serialization;
using Azure;

namespace Azure.ResourceManager
{
    internal sealed class ResponseErrorAotConverter : JsonConverter<ResponseError>
    {
        public override ResponseError Read(ref Utf8JsonReader reader, Type typeToConvert, JsonSerializerOptions options)
        {
            using var doc = JsonDocument.ParseValue(ref reader);
            var element = doc.RootElement;
            string code = null;
            string message = null;
            if (element.TryGetProperty("code"u8, out var codeProp))
                code = codeProp.GetString();
            if (element.TryGetProperty("message"u8, out var msgProp))
                message = msgProp.GetString();
            return new ResponseError(code, message);
        }

        public override void Write(Utf8JsonWriter writer, ResponseError value, JsonSerializerOptions options)
        {
            writer.WriteStartObject();
            if (value.Code != null)
            {
                writer.WriteString("code"u8, value.Code);
            }
            if (value.Message != null)
            {
                writer.WriteString("message"u8, value.Message);
            }
            writer.WriteEndObject();
        }
    }

    [JsonSourceGenerationOptions(Converters = new[] { typeof(ResponseErrorAotConverter) })]
    [JsonSerializable(typeof(ResponseError))]
    internal partial class ArmResourceManagerSerializationContext : JsonSerializerContext
    {
    }
}

